// // This module implements a 17-bit wide, 2-to-1 demultiplexer. When the select line S is 0, the output MO is set to the value of input B; when S is 1, MO is set to the value of input A.
module top_module(
    input [16:0] A,
    input [16:0] B,
    input S,
    output [16:0] MO
);assign MO = (S == 1) ? B : A;

endmodule
